INSERT INTO `member` (
    `role`, `birth`, `name`, `entry_date`, `pic`
) VALUES (
    #{ role }, #{ birth }, #{ name }, #{ entryDate }, #{ pic }
)

INSERT INTO `student`(
    `member_id`,`major_id`, `academic_year`, `semester`, `status`
) VALUES (
    #{ memberId }, #{ majorId }, #{ academicYear }, #{ semester },#{ status }
)

INSERT INTO `professor`(
    `member_id`,`major_id`, `degree`, `position`, `lab_room`, `lab_tel`, `status`
) VALUES (
    #{ memberId }, #{ majorId }, #{ degree }, #{ position }, #{ labRoom }, #{ labTel },#{ status }
)

mapper.update:
UPDATE `member`
SET
`code` = #{ code },
`password` = #{ password }
WHERE `member_id` = #{ memberId }
